package main

import "fmt"

func show(vet []int, sword int) {
    fmt.Print("[ ")
    for i := 0; i < len(vet); i++ {
        fmt.Printf("%d", vet[i])
        if i == sword-1 {
            fmt.Print("> ")
            } else {
                fmt.Print(" ")
            }
        }
    fmt.Print("]")
}

func kill(vet []int, sword *int, size *int) {
    vet[*sword] = 0
    *size--
    *sword = (*sword+1)%*size
}

func main() {
    var n, e int
    fmt.Scan(&n, &e)
    vet := make([]int, n)
    for i := 0; i < n; i++ {
        vet[i] = i+1
    }

    for n > 0 {
        kill(vet, &n, &e)
        show(vet, e)
    }

    show(vet, e)
}
